#include <iostream>
#include <string>
#include <vector>

// --- Generic template ---
template <typename T>
class DataHolder {
private:
    T data;

public:
    DataHolder(T d) : data(d) {}

    void display() const {
        std::cout << "Generic: " << data << std::endl;
    }

    T getData() const { return data; }
};

// --- Full specialization for bool ---
template <>
class DataHolder<bool> {
private:
    bool data;

public:
    DataHolder(bool d) : data(d) {}

    void display() const {
        std::cout << "Boolean: " << (data ? "true" : "false") << std::endl;
    }

    bool getData() const { return data; }
};

// --- Full specialization for std::string ---
template <>
class DataHolder<std::string> {
private:
    std::string data;

public:
    DataHolder(std::string d) : data(d) {}

    void display() const {
        std::cout << "String: \"" << data << "\" (length: " << data.length() << ")" << std::endl;
    }

    std::string getData() const { return data; }
};

// --- Template specialization for pointer types ---
template <typename T>
class DataHolder<T*> {
private:
    T* data;

public:
    DataHolder(T* d) : data(d) {}

    void display() const {
        if (data) {
            std::cout << "Pointer: " << *data << " (address: " << data << ")" << std::endl;
        } else {
            std::cout << "Pointer: null" << std::endl;
        }
    }

    T* getData() const { return data; }
};

// --- Template function specialization ---
template <typename T>
void printType(T value) {
    std::cout << "Type: " << typeid(T).name() << ", Value: " << value << std::endl;
}

// Specialization for bool
template <>
void printType<bool>(bool value) {
    std::cout << "Type: bool, Value: " << (value ? "true" : "false") << std::endl;
}

// --- Game use: specialized stat holder ---
template <typename T>
class GameStat {
private:
    std::string name;
    T value;

public:
    GameStat(std::string n, T v) : name(n), value(v) {}

    void display() const {
        std::cout << name << ": " << value << std::endl;
    }
};

// Specialization for bool (achievements)
template <>
class GameStat<bool> {
private:
    std::string name;
    bool unlocked;

public:
    GameStat(std::string n, bool u) : name(n), unlocked(u) {}

    void display() const {
        std::cout << name << ": " << (unlocked ? "✅ Unlocked" : "🔒 Locked") << std::endl;
    }

    void unlock() { unlocked = true; }
    bool isUnlocked() const { return unlocked; }
};

int main() {
    std::cout << "=== Template Specialization ===" << std::endl;

    // 1. Class specialization
    std::cout << "\n--- Class Specialization ---" << std::endl;
    DataHolder<int> intData(42);
    intData.display();

    DataHolder<bool> boolData(true);
    boolData.display();

    DataHolder<std::string> stringData("Hello, Specialization!");
    stringData.display();

    // 2. Pointer specialization
    std::cout << "\n--- Pointer Specialization ---" << std::endl;
    int value = 100;
    DataHolder<int*> ptrData(&value);
    ptrData.display();

    int* nullPtr = nullptr;
    DataHolder<int*> nullData(nullPtr);
    nullData.display();

    // 3. Function specialization
    std::cout << "\n--- Function Specialization ---" << std::endl;
    printType(42);
    printType(3.14);
    printType(true);
    printType(std::string("Hello"));

    // 4. Game use: specialized stats
    std::cout << "\n--- Game Stats with Specialization ---" << std::endl;
    GameStat<int> health("Health", 100);
    GameStat<double> mana("Mana", 50.5);
    GameStat<bool> achievement1("First Kill", true);
    GameStat<bool> achievement2("Dragon Slayer", false);

    health.display();
    mana.display();
    achievement1.display();
    achievement2.display();

    std::cout << "\n--- Why Specialize? ---" << std::endl;
    std::cout << "✅ Custom behavior for specific types" << std::endl;
    std::cout << "✅ Type-specific optimizations" << std::endl;
    std::cout << "✅ Better user experience (e.g., bool -> true/false)" << std::endl;

    return 0;
}

