#include <iostream>
#include <string>

template <typename T>
class Printer {
public:
    void print(T value) const {
        std::cout << "Generic: " << value << std::endl;
    }
};

template <>
class Printer<bool> {
public:
    void print(bool value) const {
        std::cout << "Boolean: " << (value ? "true" : "false") << std::endl;
    }
};

template <>
class Printer<std::string> {
public:
    void print(std::string value) const {
        std::cout << "String: \"" << value << "\" (length: " << value.length() << ")" << std::endl;
    }
};

int main() {
    Printer<int> intPrinter;
    intPrinter.print(42);

    Printer<bool> boolPrinter;
    boolPrinter.print(true);
    boolPrinter.print(false);

    Printer<std::string> stringPrinter;
    stringPrinter.print("Hello");

    return 0;
}
